class Codec {
public:
    string serialize(TreeNode* root) {
        string res = "";
        auto dfs = [&](auto& self, TreeNode* node) -> void {
            if (!node) {
                res += "#, ";
                return;
            }
            res += to_string(node->val) + ", ";
            self(self, node->left);
            self(self, node->right);
        };
        dfs(dfs, root);
        return res;
    }

    TreeNode* deserialize(string data) {
        stringstream ss(data);
        string item;
        vector<string> tokens;
        while (getline(ss, item, ',')) {
            // Remove spaces
            if (item[0] == ' ') item = item.substr(1);
            tokens.push_back(item);
        }
        int idx = 0;
        auto dfs = [&](auto& self) -> TreeNode* {
            if (idx >= tokens.size() || tokens[idx] == "#") {
                idx++;
                return nullptr;
            }
            TreeNode* node = new TreeNode(stoi(tokens[idx++]));
            node->left = self(self);
            node->right = self(self);
            return node;
        };
        return dfs(dfs);
    }
};

