from collections import deque, defaultdict
def verticalTraversal(root):
    if not root:
        return []
    # Map of column -> list of (row, val)
    g = defaultdict(list)
    queue = deque([(root, 0, 0)]) # (node, col, row)

    while queue:
        node, col, row = queue.popleft()
        g[col].append((row, node.val))
        if node.left: queue.append((node.left, col - 1, row + 1))
        if node.right: queue.append((node.right, col + 1, row + 1))

    res = []
    for col in sorted(g.keys()):
        # Sort level elements: first by row, then by value
        nodes = sorted(g[col], key=lambda x: (x[0], x[1]))
        res.append([val for row, val in nodes])
    return res

