vector<vector<int>> verticalTraversal(TreeNode* root) {
    if (root == nullptr) return {};
    // col -> list of pair<row, val>
    map<int, vector<pair<int, int>>> g;
    queue<tuple<TreeNode*, int, int>> q; // node, col, row
    q.push({root, 0, 0});

    while (!q.empty()) {
        auto [node, col, row] = q.front();
        q.pop();
        g[col].push_back({row, node->val});
        if (node->left) q.push({node->left, col - 1, row + 1});
        if (node->right) q.push({node->right, col + 1, row + 1});
    }

    vector<vector<int>> res;
    for (auto& [col, nodes] : g) {
        // Sort nodes by row index, then by value
        sort(nodes.begin(), nodes.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            if (a.first != b.first) return a.first < b.first;
            return a.second < b.second;
        });
        vector<int> level;
        for (auto& p : nodes) level.push_back(p.second);
        res.push_back(level);
    }
    return res;
}
